// Extract gainers and losers
const response = $json;

const allGainers = (response.top_gainers || []);
const allLosers = (response.top_losers || []);

// Parse stock data
function parseStock(s, type) {
  const pct = parseFloat(String(s.change_percentage || '0').replace('%','')) || 0;
  const vol = parseInt(s.volume) || 0;
  return { 
    ticker: s.ticker, 
    price: parseFloat(s.price) || 0, 
    changePercent: pct, 
    volume: vol, 
    type 
  };
}

// Parse all stocks
const gainers = allGainers.map(s => parseStock(s, 'gainer'));
const losers = allLosers.map(s => parseStock(s, 'loser'));

// Sort by volume
gainers.sort((a, b) => b.volume - a.volume);
losers.sort((a, b) => b.volume - a.volume);

// Get top 5 gainers, top 10 losers
const top5Gainers = gainers.slice(0, 5);
const top10Losers = losers.slice(0, 10);

// Get top 2 movers by volume (from all stocks)
const allStocks = [...gainers, ...losers];
allStocks.sort((a, b) => b.volume - a.volume);
const top2Movers = allStocks.slice(0, 2);

// Combine unique stocks (avoid duplicates)
const selectedStocks = [];
const tickers = new Set();

// Add top 2 movers first
for (const stock of top2Movers) {
  if (!tickers.has(stock.ticker)) {
    selectedStocks.push({ ...stock, category: 'top_mover' });
    tickers.add(stock.ticker);
  }
}

// Add top 5 gainers
for (const stock of top5Gainers) {
  if (!tickers.has(stock.ticker)) {
    selectedStocks.push({ ...stock, category: 'top_gainer' });
    tickers.add(stock.ticker);
  }
}

// Add top 10 losers
for (const stock of top10Losers) {
  if (!tickers.has(stock.ticker)) {
    selectedStocks.push({ ...stock, category: 'top_loser' });
    tickers.add(stock.ticker);
  }
}

// Return all stocks in a single item
return [{ json: { stocks: selectedStocks } }];

const stocks = $json.stocks;
const apiKey = 'AS9OQDLEM7W82638';

// Helper function to fetch news with error handling
async function fetchNews(ticker) {
  const url = `https://www.alphavantage.co/query?function=NEWS_SENTIMENT&tickers=${ticker}&apikey=${apiKey}&limit=10&sort=LATEST`;

  try {
    const response = await fetch(url);
    const data = await response.json();
    return data.feed || [];
  } catch (error) {
    console.log(`Error fetching news for ${ticker}:`, error.message);
    return [];
  }
}

// Helper function to filter and format news
function processNews(news) {
  // Filter news from last 24 hours
  const now = new Date();
  const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

  const recentNews = news.filter(article => {
    if (!article.time_published) return false;

    // Parse YYYYMMDDTHHMMSS format
    const year = parseInt(article.time_published.slice(0, 4));
    const month = parseInt(article.time_published.slice(4, 6)) - 1;
    const day = parseInt(article.time_published.slice(6, 8));
    const hour = parseInt(article.time_published.slice(9, 11));
    const minute = parseInt(article.time_published.slice(11, 13));
    const second = parseInt(article.time_published.slice(13, 15));

    const articleDate = new Date(year, month, day, hour, minute, second);
    return articleDate >= twentyFourHoursAgo;
  });

  if (recentNews.length > 0) {
    const first = recentNews[0];
    const raw = first.summary || first.title || "";
    const summary = raw.length > 200 ? raw.slice(0, 200) + "..." : raw;

    return {
      headline: first.title || "",
      summary: summary,
      url: first.url || "",
      publishedTime: first.time_published || "",
      sentiment: first.overall_sentiment_label || "Neutral",
      sentimentScore: first.overall_sentiment_score || 0,
      articlesCount: recentNews.length
    };
  } else {
    return {
      headline: "No recent news in last 24h",
      summary: "",
      url: "",
      publishedTime: "",
      sentiment: "N/A",
      sentimentScore: 0,
      articlesCount: 0
    };
  }
}

// Process each stock sequentially with delay to respect API rate limits
const enrichedStocks = [];

for (let i = 0; i < stocks.length; i++) {
  const stock = stocks[i];

  // Fetch news for this stock
  const news = await fetchNews(stock.ticker);
  const newsData = processNews(news);

  // Add enriched stock to results
  enrichedStocks.push({
    ...stock,
    news: newsData
  });

  // Rate limiting: wait 13 seconds between requests (5 requests per minute max for free tier)
  if (i < stocks.length - 1) {
    await new Promise(resolve => setTimeout(resolve, 13000));
  }
}

// Group by category
const topMovers = enrichedStocks.filter(s => s.category === 'top_mover');
const topGainers = enrichedStocks.filter(s => s.category === 'top_gainer');
const topLosers = enrichedStocks.filter(s => s.category === 'top_loser');

// Count stocks with news
const withNews = enrichedStocks.filter(s => s.news && s.news.articlesCount > 0);

const summary = {
  totalStocks: enrichedStocks.length,
  topMoversCount: topMovers.length,
  topGainersCount: topGainers.length,
  topLosersCount: topLosers.length,
  stocksWithNews: withNews.length,
  stocksWithoutNews: enrichedStocks.length - withNews.length,
  generatedAt: new Date().toISOString()
};

return [{
  json: {
    summary: summary,
    topMovers: topMovers,
    topGainers: topGainers,
    topLosers: topLosers,
    allStocks: enrichedStocks
  }
}];
